    else if (unidade === 'KB') fileSizeBytes = valor * 1024;
    else fileSizeBytes = valor;
  }
}

const fileSizeMB = fileSizeBytes / (1024 * 1024);

return [{
  json: {
    ...item.json,
    file_size_mb: parseFloat(fileSizeMB.toFixed(2)),
    precisa_comprimir: fileSizeMB > 16
  },
  binary: item.binary
}];

